mapper.select:
select n.resourceId,n.accessProvide,n.accessAccept,n.updateTime,n.beginTime,n.tache,n.dataDirection,n.thirdpartyProvide, n.isIssued,n.userId,n.userName,n.dataName,n.primaryDatasourceCh,n.secondaryDatasourceCh,n.primaryOrganizationCh,n.firstOrganizationCh,n.secondaryOrganizationCh from ( SELECT A.resourceId, A.accessProvide, A.accessAccept, A.updateTime, A.beginTime, A.tache, A.dataDirection, decode(thirdpartyProvide,0,accessProvide,thirdpartyProvide) thirdpartyProvide, A.isIssued, A.userId, A.userName, nvl(B.NAME, NVL(A.jobName, A.resourceId)) dataName, nvl(B.PRIMARYDATASOURCECH,'未知') primaryDatasourceCh, nvl(B.SECONDARYDATASOURCECH,'未知') secondaryDatasourceCh, nvl(B.PRIMARYORGANIZATIONCH,'未知') primaryOrganizationCh, nvl(B.FIRSTORGANIZATIONCH,'未知') firstOrganizationCh, nvl(B.SECONDARYORGANIZATIONCH,'未知') secondaryOrganizationCh FROM ( SELECT RESOURCE_ID resourceId, sum( OUTSIDE_PROVIDE ) thirdpartyProvide, sum( INSIDE_PROVIDE ) accessProvide, sum( INSIDE_ACCEPT ) accessAccept, max( CREATETIME ) updateTime, min( START_NO) beginTime, TACHE tache, DIRCTION dataDirection, TABLE_NAME, '0' isIssued, USER_ID userId, min(USER_NAME) userName, max(job_name) jobName FROM DAC_ACCESS_BILL_STATISTICS WHERE (IS_ISSUED='0' OR IS_ISSUED='' OR IS_ISSUED IS NULL) AND IS_LOCAL = '0' and nvl(SYN_INCEPT_DATA_TIME,DATA_TIME) >= TO_DATE(#{startTime},'yyyy-mm-dd hh24:mi:ss') and nvl(SYN_INCEPT_DATA_TIME,DATA_TIME) < TO_DATE(#{endTime},'yyyy-mm-dd hh24:mi:ss')
and DIRCTION = #{direction}
and USER_ID = #{userId}
GROUP BY RESOURCE_ID, TABLE_NAME, TACHE, DIRCTION, USER_ID )A left JOIN (select C.*, row_number() over (PARTITION BY yxybm ORDER BY INSERT_DATE DESC) as rn from CLASSIFY_SOURCE_TARGET C) B ON A.resourceId = B.YXYBM AND B.rn = 1 )n
and (thirdpartyProvide != accessProvide or accessProvide != accessAccept)
and thirdpartyProvide = accessProvide and accessProvide = accessAccept
and primaryOrganizationCh = #{primaryOrganization}
and firstOrganizationCh = #{firstOrganization}
and secondaryOrganizationCh = #{secondaryOrganization}
and primaryDatasourceCh = #{primaryDatasource}
and secondaryDataSourceCh = #{secondaryDataSource}
and dataName like '%'||#{dataName}||'%'

select n.resourceId,n.updateTime,n.dataTime,n.tache,n.dataDirection,n.thirdpartyProvide, n.isIssued,n.dataName,n.primaryDatasourceCh,n.secondaryDatasourceCh,n.primaryOrganizationCh,n.firstOrganizationCh,n.secondaryOrganizationCh from ( SELECT A.resourceId, A.updateTime, to_char(A.dataTime, 'yyyy-MM-dd') dataTime, A.tache, A.dataDirection, A.thirdpartyProvide thirdpartyProvide, A.isIssued, decode(B.NAME,null,A.resourceId,B.NAME) dataName, nvl(B.PRIMARYDATASOURCECH,'未知') primaryDatasourceCh, nvl(B.SECONDARYDATASOURCECH,'未知') secondaryDatasourceCh, nvl(B.PRIMARYORGANIZATIONCH,'未知') primaryOrganizationCh, nvl(B.FIRSTORGANIZATIONCH,'未知') firstOrganizationCh, nvl(B.SECONDARYORGANIZATIONCH,'未知') secondaryOrganizationCh FROM ( SELECT RESOURCE_ID resourceId, sum( OUTSIDE_PROVIDE ) thirdpartyProvide, max( CREATETIME ) updateTime, max( DATA_TIME ) dataTime, TACHE tache, DIRCTION dataDirection, TABLE_NAME, '1' isIssued FROM DAC_ACCESS_BILL_STATISTICS WHERE IS_ISSUED='1' and DATA_TIME >= TO_DATE(#{startTime},'yyyy-mm-dd hh24:mi:ss') and DATA_TIME < TO_DATE(#{endTime},'yyyy-mm-dd hh24:mi:ss') GROUP BY RESOURCE_ID, TABLE_NAME, TACHE, DIRCTION )A left JOIN CLASSIFY_INTERFACE_ALL_DATE B ON UPPER(a.TABLE_NAME) = UPPER(b.TABLENAME) )n
and primaryOrganizationCh = #{primaryOrganization}
and firstOrganizationCh = #{firstOrganization}
and secondaryOrganizationCh = #{secondaryOrganization}
and primaryDatasourceCh = #{primaryDatasource}
and secondaryDataSourceCh = #{secondaryDataSource}
and dataName like '%'||#{dataName}||'%'

select n.resourceId,n.accessProvide,n.accessAccept,n.updateTime,n.beginTime,n.tache,n.dataDirection,n.thirdpartyProvide, n.isLocal,n.userId,n.userName,n.tableNameEn,n.dataName,n.primaryDatasourceCh,n.secondaryDatasourceCh,n.primaryOrganizationCh,n.firstOrganizationCh,n.secondaryOrganizationCh from ( SELECT A.resourceId, A.accessProvide, A.accessAccept, A.updateTime, A.beginTime, A.tache, A.dataDirection, decode(thirdpartyProvide,0,accessProvide,thirdpartyProvide) thirdpartyProvide, A.isLocal, A.userId, A.userName, A.tableNameEn, nvl(B.NAME, NVL(A.jobName, A.resourceId)) dataName, nvl(B.PRIMARYDATASOURCECH,'未知') primaryDatasourceCh, nvl(B.SECONDARYDATASOURCECH,'未知') secondaryDatasourceCh, nvl(B.PRIMARYORGANIZATIONCH,'未知') primaryOrganizationCh, nvl(B.FIRSTORGANIZATIONCH,'未知') firstOrganizationCh, nvl(B.SECONDARYORGANIZATIONCH,'未知') secondaryOrganizationCh FROM ( SELECT RESOURCE_ID resourceId, sum( OUTSIDE_PROVIDE ) thirdpartyProvide, sum( INSIDE_PROVIDE ) accessProvide, sum( INSIDE_ACCEPT ) accessAccept, max( CREATETIME ) updateTime, min( START_NO) beginTime, TACHE tache, DIRCTION dataDirection, TABLE_NAME_EN tableNameEn, '1' isLocal, USER_ID userId, min(USER_NAME) userName, max(job_name) jobName FROM DAC_ACCESS_BILL_STATISTICS WHERE (IS_ISSUED='0' OR IS_ISSUED='' OR IS_ISSUED IS NULL) AND IS_LOCAL = '1' and nvl(SYN_INCEPT_DATA_TIME,DATA_TIME) >= TO_DATE(#{startTime},'yyyy-mm-dd hh24:mi:ss') and nvl(SYN_INCEPT_DATA_TIME,DATA_TIME) < TO_DATE(#{endTime},'yyyy-mm-dd hh24:mi:ss')
and DIRCTION = #{direction}
and USER_ID = #{userId}
GROUP BY RESOURCE_ID, TABLE_NAME_EN, TACHE, DIRCTION, USER_ID )A left JOIN (select C.*, row_number() over (PARTITION BY yxybm ORDER BY INSERT_DATE DESC) as rn from CLASSIFY_SOURCE_TARGET C) B ON A.resourceId = B.YXYBM and B.rn = 1 UNION ALL SELECT A.resourceId, A.accessAccept accessProvide, decode(A.outsideAccept,0,A.accessAccept,A.outsideAccept) accessAccept, A.updateTime, A.beginTime, A.tache, A.dataDirection, A.accessProvide thirdpartyProvide, '0' isLocal, A.userId, A.userName, A.tableNameEn, nvl(B.NAME, A.resourceId) dataName, nvl(B.PRIMARYDATASOURCECH,'未知') primaryDatasourceCh, nvl(B.SECONDARYDATASOURCECH,'未知') secondaryDatasourceCh, nvl(B.PRIMARYORGANIZATIONCH,'未知') primaryOrganizationCh, nvl(B.FIRSTORGANIZATIONCH,'未知') firstOrganizationCh, nvl(B.SECONDARYORGANIZATIONCH,'未知') secondaryOrganizationCh FROM ( SELECT RESOURCE_ID resourceId, sum( INSIDE_PROVIDE ) accessProvide, sum( INSIDE_ACCEPT ) accessAccept, sum( OUTSIDE_ACCEPT ) outsideAccept, max( CREATETIME ) updateTime, min( START_NO) beginTime, TACHE tache, DIRCTION dataDirection, USER_ID userId, min(USER_NAME) userName, TABLE_NAME_EN tableNameEn FROM DAC_STANDARD_BILL_STATISTICS WHERE nvl(SYN_INCEPT_DATA_TIME,DATA_TIME) >= TO_DATE(#{startTime},'yyyy-mm-dd hh24:mi:ss') and nvl(SYN_INCEPT_DATA_TIME,DATA_TIME) < TO_DATE(#{endTime},'yyyy-mm-dd hh24:mi:ss') and tache = 2 and upper(DIRCTION) = 'ODPS'
and USER_ID = #{userId}
GROUP BY RESOURCE_ID, TACHE, DIRCTION, USER_ID, TABLE_NAME_EN )A LEFT JOIN CLASSIFY_SOURCE_TARGET B ON A.resourceId = B.SJXJBM where (primaryOrganizationCh = '原始库' or secondaryOrganizationCh = '业务生产库') )n
and (thirdpartyProvide != accessProvide or accessProvide != accessAccept)
and thirdpartyProvide = accessProvide and accessProvide = accessAccept
and primaryOrganizationCh = #{primaryOrganization}
and firstOrganizationCh = #{firstOrganization}
and secondaryOrganizationCh = #{secondaryOrganization}
and primaryDatasourceCh = #{primaryDatasource}
and secondaryDataSourceCh = #{secondaryDataSource}
and dataName like '%'||#{dataName}||'%'
and tableNameEn like '%'||#{tableNameEn}||'%'

select n.resourceId,n.accessProvide,n.accessAccept,n.updateTime,n.beginTime,n.tache,n.dataDirection,n.thirdpartyProvide, n.isLocal,n.userId,n.userName,n.dataName,n.primaryDatasourceCh,n.secondaryDatasourceCh,n.primaryOrganizationCh,n.firstOrganizationCh,n.secondaryOrganizationCh from ( SELECT A.resourceId, A.accessAccept accessProvide, A.accessAccept accessAccept, A.updateTime, A.beginTime, A.tache, A.dataDirection, A.accessProvide thirdpartyProvide, '0' isLocal, A.userId, A.userName, nvl(B.NAME, A.resourceId) dataName, nvl(B.PRIMARYDATASOURCECH,'未知') primaryDatasourceCh, nvl(B.SECONDARYDATASOURCECH,'未知') secondaryDatasourceCh, nvl(B.PRIMARYORGANIZATIONCH,'未知') primaryOrganizationCh, nvl(B.FIRSTORGANIZATIONCH,'未知') firstOrganizationCh, nvl(B.SECONDARYORGANIZATIONCH,'未知') secondaryOrganizationCh FROM ( SELECT RESOURCE_ID resourceId, sum( INSIDE_PROVIDE ) accessProvide, sum( INSIDE_ACCEPT ) accessAccept, max( CREATETIME ) updateTime, min( START_NO) beginTime, TACHE tache, DIRCTION dataDirection, USER_ID userId, min(USER_NAME) userName FROM DAC_STANDARD_BILL_STATISTICS WHERE nvl(SYN_INCEPT_DATA_TIME,DATA_TIME) >= TO_DATE(#{startTime},'yyyy-mm-dd hh24:mi:ss') and nvl(SYN_INCEPT_DATA_TIME,DATA_TIME) < TO_DATE(#{endTime},'yyyy-mm-dd hh24:mi:ss') and tache = 2
and DIRCTION = #{direction}
and USER_ID = #{userId}
GROUP BY RESOURCE_ID, TACHE, DIRCTION, USER_ID )A LEFT JOIN CLASSIFY_SOURCE_TARGET B ON A.resourceId = B.SJXJBM )n where (upper(dataDirection) != 'ODPS' or (primaryOrganizationCh != '原始库' AND secondaryOrganizationCh != '业务生产库'))
and (thirdpartyProvide != accessProvide or accessProvide != accessAccept)
and thirdpartyProvide = accessProvide and accessProvide = accessAccept
and primaryOrganizationCh = #{primaryOrganization}
and firstOrganizationCh = #{firstOrganization}
and secondaryOrganizationCh = #{secondaryOrganization}
and primaryDatasourceCh = #{primaryDatasource}
and secondaryDataSourceCh = #{secondaryDataSource}
and dataName like '%'||#{dataName}||'%'

SELECT n.resourceId,n.accessProvide,n.accessAccept,n.updateTime,n.beginTime,n.tache,n.dataDirection,n.userId,n.userName, n.dataName,n.primaryDatasourceCh,n.secondaryDatasourceCh,n.primaryOrganizationCh,n.firstOrganizationCh,n.secondaryOrganizationCh FROM( SELECT A.resourceId, A.accessProvide, A.accessAccept, A.updateTime, A.beginTime, A.tache, A.dataDirection, A.userId, A.userName, nvl(B.NAME, A.resourceId) dataName, nvl(B.PRIMARYDATASOURCECH,'未知') primaryDatasourceCh, nvl(B.SECONDARYDATASOURCECH,'未知') secondaryDatasourceCh, nvl(B.PRIMARYORGANIZATIONCH,'未知') primaryOrganizationCh, nvl(B.FIRSTORGANIZATIONCH,'未知') firstOrganizationCh, nvl(B.SECONDARYORGANIZATIONCH,'未知') secondaryOrganizationCh FROM ( SELECT RESOURCE_ID resourceId, sum( INSIDE_PROVIDE ) accessProvide, sum( INSIDE_ACCEPT ) accessAccept, max( CREATETIME ) updateTime, min( START_NO) beginTime, TACHE tache, DIRCTION dataDirection, USER_ID userId, min(USER_NAME) userName FROM DAC_STANDARD_BILL_STATISTICS WHERE nvl(SYN_INCEPT_DATA_TIME,DATA_TIME) >= TO_DATE(#{startTime},'yyyy-mm-dd hh24:mi:ss') and nvl(SYN_INCEPT_DATA_TIME,DATA_TIME) < TO_DATE(#{endTime},'yyyy-mm-dd hh24:mi:ss') and tache = 1
and DIRCTION = #{direction}
and USER_ID = #{userId}
GROUP BY RESOURCE_ID, TACHE, DIRCTION, USER_ID )A LEFT JOIN (select C.*, row_number() over (PARTITION BY yxybm ORDER BY INSERT_DATE DESC) as rn from CLASSIFY_SOURCE_TARGET C) B ON A.resourceId = B.YXYBM and B.rn = 1) n
and accessProvide != accessAccept
and accessProvide = accessAccept
and primaryOrganizationCh = #{primaryOrganization}
and firstOrganizationCh = #{firstOrganization}
and secondaryOrganizationCh = #{secondaryOrganization}
and primaryDatasourceCh = #{primaryDatasource}
and secondaryDataSourceCh = #{secondaryDataSource}
and dataName like '%'||#{dataName}||'%'

SELECT sum( a.DATA_COUNT ) accessAccept, sum( p.DATA_COUNT ) accessProvide, min( a.START_NO ) beginTime, p.RESOURCE_ID resourceId, 1 tache, a.DATA_DIRECTION dataDirection, a.USER_ID userId, min(a.USER_NAME) userName, t4.NAME dataName FROM DAC_STANDARD_ACCEPTOR_BILL a LEFT JOIN DAC_ACCESS_PROVIDER_BILL p ON a.DATA_ID = p.DATA_ID AND a.SYN_INCEPT_DATA_ID = p.SYN_INCEPT_DATA_ID LEFT JOIN ( SELECT DISTINCT YXYBM, NAME FROM CLASSIFY_SOURCE_TARGET ) t4 ON p.RESOURCE_ID = T4.YXYBM WHERE p.RESOURCE_ID = #{resourceId} and a.DATA_DIRECTION = #{direction} and a.START_NO >= #{startTime} and a.START_NO < = #{endTime}
and a.USER_ID = #{userId}
GROUP BY p.RESOURCE_ID,t4.NAME,a.DATA_DIRECTION,a.USER_ID

SELECT sum( p.DATA_COUNT ) accessProvide, sum( a.DATA_COUNT ) accessAccept, min( p.START_NO ) beginTime, p.RESOURCE_ID resourceId, 2 tache, a.DATA_DIRECTION dataDirection, a.USER_ID userId, min(a.USER_NAME) userName, t4.NAME dataName FROM DAC_STORAGE_ACCEPTOR_BILL a LEFT JOIN DAC_STANDARD_PROVIDER_BILL p ON a.DATA_ID = p.DATA_ID AND a.SYN_INCEPT_DATA_ID = p.SYN_INCEPT_DATA_ID LEFT JOIN ( SELECT DISTINCT SJXJBM, NAME FROM CLASSIFY_SOURCE_TARGET ) t4 ON p.RESOURCE_ID = T4.SJXJBM WHERE p.RESOURCE_ID = #{resourceId} and a.DATA_DIRECTION = #{direction} and p.START_NO >= #{startTime} and p.START_NO < = #{endTime}
and a.USER_ID = #{userId}
GROUP BY p.RESOURCE_ID,t4.NAME,a.DATA_DIRECTION,a.USER_ID

SELECT A.billNo, A.resourceId, A.dataCount, D.dc receiveDataCount, A.beginNo, A.endNo, A.billStatus, A.sendTime, A.checkTime, A.dataSourceName, A.dataSourceType, A.accessSystem, A.jobName, A.userId, A.userName, nvl(B.NAME, NVL(A.jobName, A.resourceId)) dataName, nvl(B.PRIMARYDATASOURCECH,'未知') PRIMARYDATASOURCECH, nvl(B.SECONDARYDATASOURCECH,'未知') SECONDARYDATASOURCECH, nvl(B.PRIMARYORGANIZATIONCH,'未知') PRIMARYORGANIZATIONCH, nvl(B.FIRSTORGANIZATIONCH,'未知') FIRSTORGANIZATIONCH, nvl(B.SECONDARYORGANIZATIONCH,'未知') SECONDARYORGANIZATIONCH FROM( SELECT PROVIDER_BILL_NO billNo, RESOURCE_ID resourceId, DATA_COUNT dataCount, START_NO beginNo, END_NO endNo, BILL_STATE billStatus, DATA_SEND_TIME sendTime, DATA_CHECK_TIME checkTime, DATA_SOURCE_NAME dataSourceName, DATA_SOURCE_TYPE dataSourceType, SERVICE_IP accessSystem, JOB_NAME jobName, DATA_ID, USER_ID userId, USER_NAME userName FROM DAC_ACCESS_STORAGE_INSIDE_BILL WHERE BILL_TYPE =1 AND IS_LOCAL = '0' and DATA_SEND_TIME >= to_date(#{startTime},'yyyy-mm-dd hh24:mi:ss') and DATA_SEND_TIME <= to_date(#{endTime},'yyyy-mm-dd hh24:mi:ss')
AND DATA_SOURCE_TYPE = #{dataSourceType}
AND PROVIDER_BILL_NO LIKE '%'||#{billNo}||'%'
AND PROVIDER_NO like '%'||#{partyNo}||'%'
and DATA_SOURCE_NAME like '%'||#{dataSourceName}||'%'
and SOURCE_LOCATION like '%'||#{sourceLocation}||'%'
and DATA_ADMINISTRATOR like '%'||#{administrator}||'%'
and ADMINISTRATOR_TEL like '%'||#{administratorTel}||'%'
and START_NO like '%'||#{startNo}||'%'
and END_NO like '%'||#{endNo}||'%'
and DATA_SIZE like '%'||#{dataSize}||'%'
and RESOURCE_ID like '%'||#{resourceId}||'%'
and BILL_STATE = #{billState}
and SERVICE_IP = #{accessSystem}
and USER_ID = #{userId}
) A LEFT JOIN (select c.*, row_number() over ( PARTITION BY yxybm ORDER BY INSERT_DATE DESC ) as rn from CLASSIFY_SOURCE_TARGET c) B ON A.resourceId = B.YXYBM and B.rn = 1 LEFT JOIN (SELECT DISTINCT NVL(DATA_COUNT, 0) dc, DATA_ID FROM DAC_ACCESS_STORAGE_INSIDE_BILL WHERE BILL_TYPE = 2 AND IS_LOCAL = '0' and DATA_ARRIVE_TIME >= to_date(#{startTime},'yyyy-mm-dd hh24:mi:ss') and DATA_ARRIVE_TIME <= to_date(#{endTime},'yyyy-mm-dd hh24:mi:ss')) D ON A.DATA_ID = D.DATA_ID
and nvl(B.PRIMARYORGANIZATIONCH,'未知') = #{primaryOrganization}
and nvl(B.FIRSTORGANIZATIONCH,'未知') = #{firstOrganization}
and nvl(B.SECONDARYORGANIZATIONCH,'未知') = #{secondaryOrganization}
and nvl(B.PRIMARYDATASOURCECH,'未知') = #{primaryDatasource}
and nvl(B.SECONDARYDATASOURCECH,'未知') = #{secondaryDataSource}
and nvl(B.NAME, NVL(A.jobName, A.resourceId)) like '%'||#{dataName}||'%'

SELECT A.billNo, A.resourceId, A.dataCount, A.beginNo, A.endNo, A.billStatus, A.sendTime, A.checkTime, A.dataSourceName, A.dataSourceType, A.accessSystem, nvl(B.PRIMARYDATASOURCECH,'未知') PRIMARYDATASOURCECH, nvl(B.SECONDARYDATASOURCECH,'未知') SECONDARYDATASOURCECH, nvl(B.PRIMARYORGANIZATIONCH,'未知') PRIMARYORGANIZATIONCH, nvl(B.FIRSTORGANIZATIONCH,'未知') FIRSTORGANIZATIONCH, nvl(B.SECONDARYORGANIZATIONCH,'未知') SECONDARYORGANIZATIONCH FROM( SELECT ACCEPTOR_BILL_NO billNo, RESOURCE_ID resourceId, DATA_COUNT dataCount, START_NO beginNo, END_NO endNo, BILL_STATE billStatus, DATA_ARRIVE_TIME sendTime, DATA_CHECK_TIME checkTime, DATA_SOURCE_NAME dataSourceName, DATA_SOURCE_TYPE dataSourceType, SERVICE_IP accessSystem FROM DAC_ACCESS_STORAGE_INSIDE_BILL WHERE BILL_TYPE =2 and DATA_SEND_TIME >= to_date(#{startTime},'yyyy-mm-dd hh24:mi:ss') and DATA_SEND_TIME <= to_date(#{endTime},'yyyy-mm-dd hh24:mi:ss')
AND DATA_SOURCE_TYPE = #{dataSourceType}
AND ACCEPTOR_BILL_NO LIKE '%'||#{billNo}||'%'
AND ACCEPTRO_NO like '%'||#{partyNo}||'%'
and DATA_SOURCE_NAME like '%'||#{dataSourceName}||'%'
and SOURCE_LOCATION like '%'||#{sourceLocation}||'%'
and DATA_ADMINISTRATOR like '%'||#{administrator}||'%'
and ADMINISTRATOR_TEL like '%'||#{administratorTel}||'%'
and START_NO like '%'||#{startNo}||'%'
and END_NO like '%'||#{endNo}||'%'
and DATA_SIZE like '%'||#{dataSize}||'%'
and RESOURCE_ID like '%'||#{resourceId}||'%'
and BILL_STATE = #{billState}
and SERVICE_IP = #{accessSystem}
) A LEFT JOIN (select C.*, row_number() over (PARTITION BY yxybm ORDER BY INSERT_DATE DESC) as rn from CLASSIFY_SOURCE_TARGET C) B ON A.resourceId = B.YXYBM and B.rn = 1
and nvl(B.PRIMARYORGANIZATIONCH,'未知') = #{primaryOrganization}
and nvl(B.FIRSTORGANIZATIONCH,'未知') = #{firstOrganization}
and nvl(B.SECONDARYORGANIZATIONCH,'未知') = #{secondaryOrganization}
and nvl(B.PRIMARYDATASOURCECH,'未知') = #{primaryDatasource}
and nvl(B.SECONDARYDATASOURCECH,'未知') = #{secondaryDataSource}

SELECT A.billNo, A.resourceId, A.dataCount, A.beginNo, A.endNo, A.billStatus, A.sendTime, A.checkTime, A.dataSourceName, A.dataSourceType, A.accessSystem, nvl(B.PRIMARYDATASOURCECH,'未知') PRIMARYDATASOURCECH, nvl(B.SECONDARYDATASOURCECH,'未知') SECONDARYDATASOURCECH, nvl(B.PRIMARYORGANIZATIONCH,'未知') PRIMARYORGANIZATIONCH, nvl(B.FIRSTORGANIZATIONCH,'未知') FIRSTYORGANIZATIONCH, nvl(B.SECONDARYORGANIZATIONCH,'未知') SECONDARYORGANIZATIONCH FROM( SELECT PROVIDER_BILL_NO billNo, RESOURCE_ID resourceId, DATA_COUNT dataCount, START_NO beginNo, END_NO endNo, BILL_STATE billStatus, DATA_SEND_TIME sendTime, DATA_CHECK_TIME checkTime, DATA_SOURCE_NAME dataSourceName, DATA_SOURCE_TYPE dataSourceType, SERVICE_IP accessSystem FROM DAC_ACCESS_STORAGE_INSIDE_BILL WHERE BILL_TYPE =1 and DATA_ARRIVE_TIME >= to_date(#{startTime},'yyyy-mm-dd hh24:mi:ss') and DATA_ARRIVE_TIME <= to_date(#{endTime},'yyyy-mm-dd hh24:mi:ss')
AND DATA_SOURCE_TYPE = #{dataSourceType}
AND PROVIDER_BILL_NO LIKE '%'||#{billNo}||'%'
AND PROVIDER_NO like '%'||#{partyNo}||'%'
and DATA_SOURCE_NAME like '%'||#{dataSourceName}||'%'
and SOURCE_LOCATION like '%'||#{sourceLocation}||'%'
and DATA_ADMINISTRATOR like '%'||#{administrator}||'%'
and ADMINISTRATOR_TEL like '%'||#{administratorTel}||'%'
and START_NO like '%'||#{startNo}||'%'
and END_NO like '%'||#{endNo}||'%'
and DATA_SIZE like '%'||#{dataSize}||'%'
and RESOURCE_ID like '%'||#{resourceId}||'%'
and BILL_STATE = #{billState}
and SERVICE_IP = #{accessSystem}
) A LEFT JOIN (select C.*, row_number() over (PARTITION BY yxybm ORDER BY INSERT_DATE DESC) as rn from CLASSIFY_SOURCE_TARGET C) B ON A.resourceId = B.YXYBM and B.rn = 1
and nvl(B.PRIMARYORGANIZATIONCH,'未知') = #{primaryOrganization}
and nvl(B.FIRSTORGANIZATIONCH,'未知') = #{firstOrganization}
and nvl(B.SECONDARYORGANIZATIONCH,'未知') = #{secondaryOrganization}
and nvl(B.PRIMARYDATASOURCECH,'未知') = #{primaryDatasource}
and nvl(B.SECONDARYDATASOURCECH,'未知') = #{secondaryDataSource}

SELECT A.billNo, A.resourceId, A.dataCount, D.dc receiveDataCount, A.beginNo, A.endNo, A.billStatus, A.sendTime, A.checkTime, A.dataSourceName, A.dataSourceType, A.accessSystem, A.jobName, A.userId, A.userName, nvl(B.NAME, NVL(A.jobName, A.resourceId)) dataName, nvl(B.PRIMARYDATASOURCECH,'未知') PRIMARYDATASOURCECH, nvl(B.SECONDARYDATASOURCECH,'未知') SECONDARYDATASOURCECH, nvl(B.PRIMARYORGANIZATIONCH,'未知') PRIMARYORGANIZATIONCH, nvl(B.FIRSTORGANIZATIONCH,'未知') FIRSTORGANIZATIONCH, nvl(B.SECONDARYORGANIZATIONCH,'未知') SECONDARYORGANIZATIONCH FROM( SELECT PROVIDER_BILL_NO billNo, RESOURCE_ID resourceId, DATA_COUNT dataCount, START_NO beginNo, END_NO endNo, BILL_STATE billStatus, DATA_SEND_TIME sendTime, DATA_CHECK_TIME checkTime, DATA_SOURCE_NAME dataSourceName, DATA_SOURCE_TYPE dataSourceType, SERVICE_IP accessSystem, JOB_NAME jobName, DATA_ID, SYN_INCEPT_DATA_ID, USER_ID userId, USER_NAME userName FROM DAC_ACCESS_PROVIDER_BILL WHERE DATA_SEND_TIME >= to_date(#{startTime},'yyyy-mm-dd hh24:mi:ss') and DATA_SEND_TIME <= to_date(#{endTime},'yyyy-mm-dd hh24:mi:ss') AND DATA_DIRECTION = 2
AND DATA_SOURCE_TYPE = #{dataSourceType}
AND PROVIDER_BILL_NO LIKE '%'||#{billNo}||'%'
AND PROVIDER_NO like '%'||#{partyNo}||'%'
and DATA_SOURCE_NAME like '%'||#{dataSourceName}||'%'
and SOURCE_LOCATION like '%'||#{sourceLocation}||'%'
and DATA_ADMINISTRATOR like '%'||#{administrator}||'%'
and ADMINISTRATOR_TEL like '%'||#{administratorTel}||'%'
and START_NO like '%'||#{startNo}||'%'
and END_NO like '%'||#{endNo}||'%'
and DATA_SIZE like '%'||#{dataSize}||'%'
and RESOURCE_ID like '%'||#{resourceId}||'%'
and BILL_STATE = #{billState}
and SERVICE_IP = #{accessSystem}
and USER_ID = #{userId}
) A LEFT JOIN (select C.*, row_number() over (PARTITION BY yxybm ORDER BY INSERT_DATE DESC) as rn from CLASSIFY_SOURCE_TARGET C) B ON A.resourceId = B.YXYBM and B.rn = 1 left join (SELECT DISTINCT NVL(DATA_COUNT, 0) dc, DATA_ID, SYN_INCEPT_DATA_ID FROM DAC_STANDARD_ACCEPTOR_BILL WHERE BILL_TYPE = 2 AND DATA_ARRIVE_TIME >= to_date(#{startTime},'yyyy-mm-dd hh24:mi:ss')) D on D.DATA_ID = A.DATA_ID and D.SYN_INCEPT_DATA_ID = A.SYN_INCEPT_DATA_ID
and nvl(B.PRIMARYORGANIZATIONCH,'未知') = #{primaryOrganization}
