and tache = #{tache} and nvl(SYN_INCEPT_DATA_TIME,DATA_TIME) >= TO_DATE(#{startTime},'yyyy-mm-dd hh24:mi:ss') and nvl(SYN_INCEPT_DATA_TIME,DATA_TIME) < TO_DATE(#{endTime},'yyyy-mm-dd hh24:mi:ss')
