and dirction = #{direction}
and USER_ID = #{userId}
GROUP BY ACCESS_SYSTEM, DATA_SOURCE, RESOURCE_ID, TACHE, DIRCTION, USER_ID )A LEFT JOIN (select C.*, row_number() over (PARTITION BY yxybm ORDER BY INSERT_DATE DESC) as rn from CLASSIFY_SOURCE_TARGET C) B ON A.resourceId = B.YXYBM and B.rn = 1

SELECT A.accessSystem, A.dataSourceName, A.resourceId, A.accessProvide, A.accessAccept, A.updateTime, A.beginNo, A.tache, A.dataDirection, A.userId, A.userName, nvl(B.NAME, A.resourceId) dataName FROM ( SELECT ACCESS_SYSTEM accessSystem, DATA_SOURCE dataSourceName, RESOURCE_ID resourceId, sum( INSIDE_PROVIDE ) accessProvide, sum( INSIDE_ACCEPT ) accessAccept, min( CREATETIME ) updateTime, min(start_no) beginNo, TACHE tache, DIRCTION dataDirection, USER_ID userId, min(USER_NAME) userName FROM DAC_STANDARD_BILL_STATISTICS WHERE resource_id = #{resourceId} and tache = #{tache} and nvl(SYN_INCEPT_DATA_TIME,DATA_TIME) >= TO_DATE(#{startTime},'yyyy-mm-dd hh24:mi:ss') and nvl(SYN_INCEPT_DATA_TIME,DATA_TIME) < TO_DATE(#{endTime},'yyyy-mm-dd hh24:mi:ss')
and USER_ID = #{userId}
GROUP BY ACCESS_SYSTEM, DATA_SOURCE, RESOURCE_ID, TACHE, DIRCTION, USER_ID )A LEFT JOIN (select C.*, row_number() over (PARTITION BY yxybm ORDER BY INSERT_DATE DESC) as rn from CLASSIFY_SOURCE_TARGET C) B ON A.resourceId = B.YXYBM and B.rn = 1

SELECT A.accessSystem, A.dataSourceName, A.resourceId, A.accessProvide, A.accessAccept, A.updateTime, A.beginNo, A.tache, A.dataDirection, A.userId, A.userName, nvl(B.NAME, A.resourceId) dataName FROM ( SELECT ACCESS_SYSTEM accessSystem, DATA_SOURCE dataSourceName, RESOURCE_ID resourceId, sum( INSIDE_PROVIDE ) accessProvide, sum( INSIDE_ACCEPT ) accessAccept, min( CREATETIME ) updateTime, min(start_no) beginNo, TACHE tache, DIRCTION dataDirection, USER_ID userId, min(USER_NAME) userName FROM DAC_STANDARD_BILL_STATISTICS WHERE resource_id = #{resourceId} and tache = #{tache} and nvl(SYN_INCEPT_DATA_TIME,DATA_TIME) >= TO_DATE(#{startTime},'yyyy-mm-dd hh24:mi:ss') and nvl(SYN_INCEPT_DATA_TIME,DATA_TIME) < TO_DATE(#{endTime},'yyyy-mm-dd hh24:mi:ss')
and USER_ID = #{userId}
GROUP BY ACCESS_SYSTEM, DATA_SOURCE, RESOURCE_ID, TACHE, DIRCTION, USER_ID )A LEFT JOIN ( SELECT DISTINCT SJXJBM, NAME FROM CLASSIFY_SOURCE_TARGET) B ON A.resourceId = B.SJXJBM

