SELECT A.resourceId, A.thirdpartyProvide, A.accessProvide, A.accessAccept, A.updateTime, A.tache, A.dataDirection, A.userId, A.userName, nvl(B.NAME, nvl(A.jobName, A.resourceId)) dataName FROM ( SELECT RESOURCE_ID resourceId, sum( OUTSIDE_PROVIDE ) thirdpartyProvide, sum( INSIDE_PROVIDE ) accessProvide, sum( INSIDE_ACCEPT ) accessAccept, max( CREATETIME ) updateTime, TACHE tache, DIRCTION dataDirection, max(JOB_NAME) jobName, USER_ID userId, min(USER_NAME) userName FROM DAC_ACCESS_BILL_STATISTICS WHERE resource_id = #{resourceId} and DIRCTION = #{direction} and tache = #{tache} and DATA_TIME >= TO_DATE(#{startTime},'yyyy-mm-dd hh24:mi:ss') and DATA_TIME < TO_DATE(#{endTime},'yyyy-mm-dd hh24:mi:ss')
and USER_ID = #{userId}
GROUP BY RESOURCE_ID, TACHE, DIRCTION, USER_ID )A LEFT JOIN (select C.*, row_number() over (PARTITION BY yxybm ORDER BY INSERT_DATE DESC) as rn from CLASSIFY_SOURCE_TARGET C) B ON A.resourceId = B.YXYBM and B.rn = 1

