,#{system,jdbcType=NUMERIC},#{status,jdbcType=NUMERIC},#{id,jdbcType=VARCHAR},sysdate)

mapper.select:
SELECT P.RESOURCE_ID resourceId, P.TABLE_NAME_EN tableNameEn, P.DATA_SOURCE_NAME dataSource, P.SERVICE_IP accessSystem, P.DATA_DIRECTION direction, P.USER_ID userId, P.USER_NAME userName, P.INSIDE_PROVIDE insideProvide, P.startNo, P.jobName, P.isLocal, A.INSIDE_ACCEPT insideAccess, O.OUTSIDE_PROVIDE outSideProvide, 2 tache, '0' isIssued, to_date ( #{date1}, 'yyyy-mm-dd HH24:mi:ss' ) dataTime, P.SYN_INCEPT_DATA_TIME synInceptDataTime FROM ( SELECT RESOURCE_ID, TABLE_NAME_EN, DATA_SOURCE_NAME, SERVICE_IP, DATA_DIRECTION, min(USER_ID) USER_ID, min(USER_NAME) USER_NAME, sum( DATA_COUNT ) INSIDE_PROVIDE, min( START_NO ) startNo, max(JOB_NAME) jobName, max(IS_LOCAL) isLocal, SYN_INCEPT_DATA_TIME FROM DAC_ACCESS_STORAGE_INSIDE_BILL WHERE BILL_TYPE = 1 AND RESOURCE_ID = #{resourceId} AND DATA_DIRECTION = #{dataDirection} AND DATA_ARRIVE_TIME >= to_date( #{ date1 }, 'yyyy-mm-dd HH24:mi:ss' ) AND DATA_ARRIVE_TIME < to_date( #{ date2 }, 'yyyy-mm-dd HH24:mi:ss' )
and USER_ID = #{userId}
GROUP BY RESOURCE_ID, TABLE_NAME_EN, DATA_SOURCE_NAME, SERVICE_IP, DATA_DIRECTION, SYN_INCEPT_DATA_TIME ) P LEFT JOIN ( SELECT RESOURCE_ID, TABLE_NAME_EN, DATA_SOURCE_NAME, SERVICE_IP, DATA_DIRECTION, sum( DATA_COUNT ) INSIDE_ACCEPT, SYN_INCEPT_DATA_TIME FROM DAC_ACCESS_STORAGE_INSIDE_BILL WHERE BILL_TYPE = 2 AND RESOURCE_ID = #{resourceId} AND DATA_DIRECTION = #{dataDirection} AND DATA_ARRIVE_TIME >= to_date( #{ date1 }, 'yyyy-mm-dd HH24:mi:ss' ) AND DATA_ARRIVE_TIME < to_date( #{ date2 }, 'yyyy-mm-dd HH24:mi:ss' ) GROUP BY RESOURCE_ID, TABLE_NAME_EN, DATA_SOURCE_NAME, SERVICE_IP, DATA_DIRECTION, SYN_INCEPT_DATA_TIME ) A ON P.RESOURCE_ID = A.RESOURCE_ID AND P.DATA_SOURCE_NAME = A.DATA_SOURCE_NAME AND P.SERVICE_IP = A.SERVICE_IP AND P.DATA_DIRECTION = A.DATA_DIRECTION AND P.SYN_INCEPT_DATA_TIME = A.SYN_INCEPT_DATA_TIME LEFT JOIN ( SELECT RESOURCE_ID, TABLE_NAME_EN, DATA_SOURCE_NAME, SERVICE_IP, DATA_DIRECTION, SUM( DATA_COUNT ) OUTSIDE_PROVIDE FROM ( SELECT RESOURCE_ID, TABLE_NAME_EN, DATA_SOURCE_NAME, SERVICE_IP, DATA_DIRECTION, DATA_ID FROM DAC_ACCESS_ACCEPTOR_BILL WHERE RESOURCE_ID = #{resourceId} AND DATA_DIRECTION = #{dataDirection} and DATA_ARRIVE_TIME >= to_date( #{ date1 }, 'yyyy-mm-dd HH24:mi:ss' ) AND DATA_ARRIVE_TIME < to_date( #{ date2 }, 'yyyy-mm-dd HH24:mi:ss' ) ) A INNER JOIN ( SELECT DATA_ID, DATA_COUNT FROM DAC_ACCESS_PROVIDER_BILL WHERE DATA_SEND_TIME >= to_date( #{ date3 }, 'yyyy-mm-dd HH24:mi:ss' ) AND DATA_SEND_TIME < to_date( #{ date2 }, 'yyyy-mm-dd HH24:mi:ss' ) ) P ON A.DATA_ID = P.DATA_ID GROUP BY RESOURCE_ID, TABLE_NAME_EN, DATA_SOURCE_NAME, SERVICE_IP, DATA_DIRECTION ) O ON P.RESOURCE_ID = O.RESOURCE_ID AND P.DATA_SOURCE_NAME = O.DATA_SOURCE_NAME AND P.SERVICE_IP = O.SERVICE_IP AND P.DATA_DIRECTION = O.DATA_DIRECTION

SELECT RESOURCE_ID resourceId, DATA_SOURCE_NAME dataSource, SERVICE_IP accessSystem, DATA_DIRECTION direction, sys_code sysCode, data_source dataSourceCode, INSIDE_PROVIDE insideProvide, startNo, INSIDE_ACCEPT insideAccess, 1 tache, to_date( #{ date1 }, 'yyyy-mm-dd HH24:mi:ss' ) dataTime, USER_ID userId, USER_NAME userName, SYN_INCEPT_DATA_TIME synInceptDataTime FROM ( SELECT A.RESOURCE_ID, A.DATA_SOURCE_NAME, A.SERVICE_IP, A.DATA_DIRECTION, A.sys_code, A.data_source, MIN(A.USER_ID) USER_ID, MIN(A.USER_NAME) USER_NAME, sum( A.DATA_COUNT ) INSIDE_ACCEPT, sum( B.DATA_COUNT ) INSIDE_PROVIDE, MIN(A.START_NO) startNo, A.SYN_INCEPT_DATA_TIME FROM DAC_STANDARD_ACCEPTOR_BILL A LEFT JOIN ( SELECT DATA_ID, DATA_COUNT, SYN_INCEPT_DATA_ID FROM DAC_ACCESS_PROVIDER_BILL WHERE DATA_SEND_TIME >= to_date( #{ date3 }, 'yyyy-mm-dd HH24:mi:ss' ) AND DATA_SEND_TIME < to_date( #{ date2 }, 'yyyy-mm-dd HH24:mi:ss' ) AND RESOURCE_ID = #{resourceId} ) B ON A.DATA_ID = B.DATA_ID and A.SYN_INCEPT_DATA_ID=B.SYN_INCEPT_DATA_ID WHERE A.DATA_ARRIVE_TIME >= to_date( #{ date1 }, 'yyyy-mm-dd HH24:mi:ss' ) AND A.DATA_ARRIVE_TIME < to_date( #{ date2 }, 'yyyy-mm-dd HH24:mi:ss' ) AND A.RESOURCE_ID = #{resourceId} AND A.DATA_DIRECTION = #{direction}
and A.USER_ID = #{userId}
GROUP BY A.RESOURCE_ID, A.DATA_SOURCE_NAME, A.SERVICE_IP, A.DATA_DIRECTION, A.SYS_CODE, A.DATA_SOURCE, A.SYN_INCEPT_DATA_TIME )

SELECT P.RESOURCE_ID resourceId, A.TABLE_NAME_EN tableNameEn, P.DATA_SOURCE_NAME dataSource, P.SERVICE_IP accessSystem, P.PLATFORM direction, P.SYS_CODE sysCode, P.DATA_SOURCE dataSourceCode, P.INSIDE_PROVIDE insideProvide, P.startNo, A.INSIDE_ACCEPT insideAccess, 2 tache, to_date( #{ date1 }, 'yyyy-mm-dd HH24:mi:ss' ) dataTime, P.USER_ID userId, P.USER_NAME userName, P.SYN_INCEPT_DATA_TIME synInceptDataTime, O.OUTSIDE_ACCEPT outsideAccept FROM ( SELECT RESOURCE_ID, DATA_SOURCE_NAME, SERVICE_IP, DATA_DIRECTION, SYS_CODE, DATA_SOURCE, PLATFORM, sum( DATA_COUNT ) INSIDE_PROVIDE, min( START_NO ) startNo, min(USER_ID) USER_ID, min(USER_NAME) USER_NAME, SYN_INCEPT_DATA_TIME FROM DAC_STANDARD_PROVIDER_BILL WHERE DATA_SEND_TIME >= to_date( #{ date1 }, 'yyyy-mm-dd HH24:mi:ss' ) AND DATA_SEND_TIME < to_date( #{ date2 }, 'yyyy-mm-dd HH24:mi:ss' ) AND RESOURCE_ID = #{resourceId} AND upper(PLATFORM) = upper(#{direction})
and USER_ID = #{userId}
GROUP BY RESOURCE_ID, DATA_SOURCE_NAME, SERVICE_IP, DATA_DIRECTION, SYS_CODE, DATA_SOURCE, PLATFORM, SYN_INCEPT_DATA_TIME ) P LEFT JOIN ( SELECT RESOURCE_ID, TABLE_NAME_EN, DATA_SOURCE_NAME, SERVICE_IP, DATA_DIRECTION, SYS_CODE, DATA_SOURCE, PLATFORM, sum( DATA_COUNT ) INSIDE_ACCEPT, SYN_INCEPT_DATA_TIME FROM DAC_STORAGE_ACCEPTOR_BILL WHERE DATA_ARRIVE_TIME >= to_date( #{ date1 }, 'yyyy-mm-dd HH24:mi:ss' ) AND DATA_ARRIVE_TIME < to_date( #{ date2 }, 'yyyy-mm-dd HH24:mi:ss' ) AND RESOURCE_ID = #{resourceId} AND upper(PLATFORM) = upper(#{direction}) GROUP BY RESOURCE_ID, TABLE_NAME_EN, DATA_SOURCE_NAME, SERVICE_IP, DATA_DIRECTION, SYS_CODE, DATA_SOURCE, PLATFORM, SYN_INCEPT_DATA_TIME ) A ON P.RESOURCE_ID = A.RESOURCE_ID AND P.DATA_SOURCE_NAME = A.DATA_SOURCE_NAME AND P.SERVICE_IP = A.SERVICE_IP AND P.SYS_CODE=A.SYS_CODE AND P.DATA_SOURCE = A.DATA_SOURCE AND P.PLATFORM = A.PLATFORM AND P.SYN_INCEPT_DATA_TIME = A.SYN_INCEPT_DATA_TIME LEFT JOIN ( SELECT RESOURCE_ID, DATA_SOURCE_NAME, SERVICE_IP, DATA_DIRECTION, SYS_CODE, DATA_SOURCE, PLATFORM, SYN_INCEPT_DATA_TIME, SUM( DATA_COUNT ) OUTSIDE_ACCEPT FROM DAC_STORAGE_ACCEPTOR_BILL S WHERE DATA_ARRIVE_TIME < to_date ( #{date2}, 'yyyy-mm-dd HH24:mi:ss' ) AND RESOURCE_ID = #{resourceId} AND upper(PLATFORM) = upper(#{direction}) AND EXISTS (SELECT 1 FROM DAC_STORAGE_PROVIDER_BILL WHERE DATA_SEND_TIME >= to_date ( #{date1}, 'yyyy-mm-dd HH24:mi:ss' ) AND DATA_SEND_TIME < to_date ( #{date2}, 'yyyy-mm-dd HH24:mi:ss' ) AND DATA_ID = S.DATA_ID AND SYN_INCEPT_DATA_ID = S.SYN_INCEPT_DATA_ID) GROUP BY RESOURCE_ID, DATA_SOURCE_NAME, SERVICE_IP, DATA_DIRECTION, SYS_CODE, DATA_SOURCE, PLATFORM, SYN_INCEPT_DATA_TIME ) O ON P.RESOURCE_ID = O.RESOURCE_ID AND P.DATA_SOURCE_NAME = O.DATA_SOURCE_NAME AND P.SERVICE_IP = O.SERVICE_IP AND P.SYS_CODE=O.SYS_CODE AND P.DATA_SOURCE = O.DATA_SOURCE AND P.PLATFORM = O.PLATFORM AND P.SYN_INCEPT_DATA_TIME = O.SYN_INCEPT_DATA_TIME

select days.dataTime beginTime, nvl(sum(m.thirdpartyProvide), 0) thirdpartyProvide, nvl(sum(m.accessProvide), 0) accessProvide, nvl(sum(m.accessAccept), 0) accessAccept from (select to_char(to_date(#{endTime}, 'yyyy-MM-dd') - LEVEL + 1, 'yyyy-MM-dd') dataTime from dual connect by LEVEL <= #{days}) days left join (SELECT to_char(DATA_TIME, 'yyyy-MM-dd') dataTime, ACCESS_SYSTEM accessSystem, DATA_SOURCE dataSourceName, RESOURCE_ID resourceId, decode(OUTSIDE_PROVIDE, 0, INSIDE_PROVIDE, OUTSIDE_PROVIDE) thirdpartyProvide, INSIDE_PROVIDE accessProvide, INSIDE_ACCEPT accessAccept, DIRCTION dataDirection FROM DAC_ACCESS_BILL_STATISTICS where resource_id = #{resourceId} and tache = 2
and is_local = #{isLocal}
and dirction = #{direction}
) m on days.dataTime = m.dataTime group by days.dataTime order by days.dataTime
